Rule.Source:
  import java.util.ArrayList;
  import sailpoint.object.Custom;
  import sailpoint.object.Identity;
  import sailpoint.tools.Util;
  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;

  /**
		 * List all Contractor user types updated in custom object	
		 * @return list of all Contractor user types 
		 */
  static Log logger = LogFactory.getLog("rule.CreateContractor");
  logger.debug("Entering VendorName AllowedValues Rule");
  ArrayList vendorCompany= new ArrayList();
  Custom allowedValues = context.getObjectByName(Custom.class,"Ascension-Custom-ContractorConfiguration");

  if (allowedValues != null && null != allowedValues.get("VendorName")) {
    vendorCompany = allowedValues.get("VendorName");
  }
  
  if(null != allowedValues){
    context.decache(allowedValues);
  }

  if (form.getField("dbFields") != null @and form.getField("dbFields").getValue() != null @and form.getField("domain") != null @and form.getField("domain").getValue() != null) {

    List vendorList = form.getField("dbFields").getValue().get("ps_ahhr_sailp_v_vw");
    if(!Util.isEmpty(vendorList)){
	if(form.getField("contractorName")!=null @and form.getField("contractorName").getValue()!=null) {
          Identity identity = context.getObjectByName(Identity.class, form.getField("contractorName").getValue());
          if (identity != null @and identity.getAttribute("vendorName")!=null) {
          	vendorCompany.add(identity.getAttribute("vendorName"));          
          }
      } 
      for (String eachVendor : vendorList ) {
        if(eachVendor.startsWith(form.getField("domain").getValue())) {
          vendorCompany.add(eachVendor.split("\\|")[1]);
        }
      }
    }
  }

  
  if(vendorCompany == null){
    vendorCompany = new ArrayList();  
  }
  Collections.sort(vendorCompany);
  logger.debug("Exiting Location AllowedValues Rule");
  return vendorCompany;
